//========================================================================================================================================================================================================200
//	DEFINE/INCLUDE
//========================================================================================================================================================================================================200

#include <cuda.h>
#include <stdio.h>
#include <stdlib.h>

#include "../common.h"
#include "../util/cuda/cuda.h"
#include "../util/timer/timer.h"
#include "./kernel_gpu_cuda_wrapper_2.h"

//========================================================================================================================================================================================================200
//	KERNEL
//========================================================================================================================================================================================================200

__global__ void 
findRangeK(	long maxheight,
			knode *knodesD,
			long knodes_elem,
			long *currKnodeD,
			long *offsetD,
			long *lastKnodeD,
			long *offset_2D,
			int *startD,
			int *endD,
			int *recstartD,
			int *reclengthD,
			int count)
{
	// block ID
	int bid = blockIdx.x;

	if(bid < count){

		// thread ID
		int thid = threadIdx.x;

		// process levels of the tree
		int i;
		for(i = 0; i < maxheight; i++){

			if((knodesD[currKnodeD[bid]].keys[thid] <= startD[bid]) && (knodesD[currKnodeD[bid]].keys[thid+1] > startD[bid])){
				if(knodesD[currKnodeD[bid]].indices[thid] < knodes_elem){
					offsetD[bid] = knodesD[currKnodeD[bid]].indices[thid];
				}
			}
			if((knodesD[lastKnodeD[bid]].keys[thid] <= endD[bid]) && (knodesD[lastKnodeD[bid]].keys[thid+1] > endD[bid])){
				if(knodesD[lastKnodeD[bid]].indices[thid] < knodes_elem){
					offset_2D[bid] = knodesD[lastKnodeD[bid]].indices[thid];
				}
			}

			__syncthreads();

			// set for next tree level
			if(thid == 0){
				currKnodeD[bid] = offsetD[bid];
				lastKnodeD[bid] = offset_2D[bid];
			}

			__syncthreads();

		}

		// Find the index of the starting record
		if(knodesD[currKnodeD[bid]].keys[thid] == startD[bid]){
			recstartD[bid] = knodesD[currKnodeD[bid]].indices[thid];
		}

		__syncthreads();

		// Find the index of the ending record
		if(knodesD[lastKnodeD[bid]].keys[thid] == endD[bid]){
			reclengthD[bid] = knodesD[lastKnodeD[bid]].indices[thid] - recstartD[bid] + 1;
		}

	}
}

//========================================================================================================================================================================================================200
//	WRAPPER FUNCTION
//========================================================================================================================================================================================================200

#ifdef __cplusplus
extern "C" {
#endif

void 
kernel_gpu_cuda_wrapper_2(	knode *knodes,
							long knodes_elem,
							long knodes_mem,

							int order,
							long maxheight,
							int count,

							long *currKnode,
							long *offset,
							long *lastKnode,
							long *offset_2,
							int *start,
							int *end,
							int *recstart,
							int *reclength)
{

	//======================================================================================================================================================150
	//	Variables
	//======================================================================================================================================================150

	// timer
	long long time0;
	long long time1;
	long long time2;
	long long time3;
	long long time4;
	long long time5;

	time0 = get_time();

	//======================================================================================================================================================150
	//	CUDA SETUP
	//======================================================================================================================================================150

	setdevice();

	time1 = get_time();

	//======================================================================================================================================================150
	//	INPUTS
	//======================================================================================================================================================150

	// knodes
	knode *knodesD;
	cudaMalloc((void**)&knodesD, knodes_mem);
	cudaMemcpy(knodesD, knodes, knodes_mem, cudaMemcpyHostToDevice);

	// currKnode
	long *currKnodeD;
	cudaMalloc((void**)&currKnodeD, count*sizeof(long));
	cudaMemcpy(currKnodeD, currKnode, count*sizeof(long), cudaMemcpyHostToDevice);

	// offset
	long *offsetD;
	cudaMalloc((void**)&offsetD, count*sizeof(long));
	cudaMemcpy(offsetD, offset, count*sizeof(long), cudaMemcpyHostToDevice);

	// lastKnode
	long *lastKnodeD;
	cudaMalloc((void**)&lastKnodeD, count*sizeof(long));
	cudaMemcpy(lastKnodeD, lastKnode, count*sizeof(long), cudaMemcpyHostToDevice);

	// offset_2
	long *offset_2D;
	cudaMalloc((void**)&offset_2D, count*sizeof(long));
	cudaMemcpy(offset_2D, offset_2, count*sizeof(long), cudaMemcpyHostToDevice);

	// start
	int *startD;
	cudaMalloc((void**)&startD, count*sizeof(int));
	cudaMemcpy(startD, start, count*sizeof(int), cudaMemcpyHostToDevice);

	// end
	int *endD;
	cudaMalloc((void**)&endD, count*sizeof(int));
	cudaMemcpy(endD, end, count*sizeof(int), cudaMemcpyHostToDevice);

	// recstart
	int *recstartD;
	cudaMalloc((void**)&recstartD, count*sizeof(int));
	cudaMemcpy(recstartD, recstart, count*sizeof(int), cudaMemcpyHostToDevice);

	// reclength
	int *reclengthD;
	cudaMalloc((void**)&reclengthD, count*sizeof(int));
	cudaMemcpy(reclengthD, reclength, count*sizeof(int), cudaMemcpyHostToDevice);

	time2 = get_time();

	//======================================================================================================================================================150
	//	KERNEL
	//======================================================================================================================================================150

	int threadsPerBlock;
	threadsPerBlock = order < 1024 ? order : 1024;

	dim3 dimGrid(count, 1);
	dim3 dimBlock(threadsPerBlock, 1);

	findRangeK<<<dimGrid, dimBlock>>>(	maxheight,
										knodesD,
										knodes_elem,
										currKnodeD,
										offsetD,
										lastKnodeD,
										offset_2D,
										startD,
										endD,
										recstartD,
										reclengthD,
										count);

	cudaDeviceSynchronize();
	checkCUDAError("findRangeK");

	time3 = get_time();

	//======================================================================================================================================================150
	//	COPY RESULTS BACK
	//======================================================================================================================================================150

	cudaMemcpy(recstart, recstartD, count*sizeof(int), cudaMemcpyDeviceToHost);
	cudaMemcpy(reclength, reclengthD, count*sizeof(int), cudaMemcpyDeviceToHost);

	time4 = get_time();

	//======================================================================================================================================================150
	//	FREE MEMORY
	//======================================================================================================================================================150

	cudaFree(knodesD);
	cudaFree(currKnodeD);
	cudaFree(offsetD);
	cudaFree(lastKnodeD);
	cudaFree(offset_2D);
	cudaFree(startD);
	cudaFree(endD);
	cudaFree(recstartD);
	cudaFree(reclengthD);

	time5 = get_time();

	//======================================================================================================================================================150
	//	DISPLAY TIMING
	//======================================================================================================================================================150

	printf("Time spent in different stages of GPU_CUDA KERNEL:\n");

	printf("%15.12f s, %15.12f % : GPU: SET DEVICE / DRIVER INIT\n",	(float) (time1-time0) / 1000000, (float) (time1-time0) / (float) (time5-time0) * 100);
	printf("%15.12f s, %15.12f % : GPU: ALLOCATE + TRANSFER IN\n",		(float) (time2-time1) / 1000000, (float) (time2-time1) / (float) (time5-time0) * 100);
	printf("%15.12f s, %15.12f % : GPU: KERNEL\n",						(float) (time3-time2) / 1000000, (float) (time3-time2) / (float) (time5-time0) * 100);
	printf("%15.12f s, %15.12f % : GPU: TRANSFER OUT\n",				(float) (time4-time3) / 1000000, (float) (time4-time3) / (float) (time5-time0) * 100);
	printf("%15.12f s, %15.12f % : GPU: FREE\n",						(float) (time5-time4) / 1000000, (float) (time5-time4) / (float) (time5-time0) * 100);

	printf("Total time:\n");
	printf("%.12f s\n", 												(float) (time5-time0) / 1000000);

}

#ifdef __cplusplus
}
#endif

