#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <sys/time.h>
#include <cuda.h>

#include "backprop.h"

////////////////////////////////////////////////////////////////////////////////

extern void bpnn_layerforward(float *l1, float *l2, float **conn, int n1, int n2);
extern void bpnn_output_error(float *delta, float *target, float *output, int nj, float *err);
extern void bpnn_hidden_error(float *delta_h, int nh, float *delta_o, int no, float **who, float *hidden, float *err);
extern void bpnn_adjust_weights(float *delta, int ndelta, float *ly, int nly, float **w, float **oldw);

extern int setup(int argc, char** argv);
extern float **alloc_2d_dbl(int m, int n);
extern float squash(float x);

double gettime() {
  struct timeval t;
  gettimeofday(&t,NULL);
  return t.tv_sec+t.tv_usec*1e-6;
}

////////////////////////////////////////////////////////////////////////////////
// CUDA Kernels
////////////////////////////////////////////////////////////////////////////////

// Kernel for layerforward: each thread computes one output unit
__global__ void bpnn_layerforward_cuda(float *l1, float *l2, float *conn_flat, int n1, int n2)
{
    // j is the index of the output unit (1-indexed)
    int j = blockIdx.x * blockDim.x + threadIdx.x + 1;

    if (j <= n2) {
        float sum = 0.0f;
        for (int k = 0; k <= n1; k++) {
            // conn[k][j] in flat layout: conn_flat[k * (n2+1) + j]
            sum += conn_flat[k * (n2 + 1) + j] * l1[k];
        }
        l2[j] = 1.0f / (1.0f + expf(-sum));
    }
}

// Kernel for adjust_weights: each thread handles one (j, k) pair
__global__ void bpnn_adjust_weights_cuda(float *delta, int ndelta, float *ly, int nly,
                                          float *w_flat, float *oldw_flat)
{
    // j: 1..ndelta, k: 0..nly
    int j = blockIdx.x * blockDim.x + threadIdx.x + 1;
    int k = blockIdx.y * blockDim.y + threadIdx.y;

    if (j <= ndelta && k <= nly) {
        // w[k][j] = w_flat[k * (ndelta+1) + j]
        // oldw[k][j] = oldw_flat[k * (ndelta+1) + j]
        float new_dw = (ETA * delta[j] * ly[k]) + (MOMENTUM * oldw_flat[k * (ndelta + 1) + j]);
        w_flat[k * (ndelta + 1) + j] += new_dw;
        oldw_flat[k * (ndelta + 1) + j] = new_dw;
    }
}

////////////////////////////////////////////////////////////////////////////////
// Helper: flatten 2D array to 1D
////////////////////////////////////////////////////////////////////////////////
static float* flatten_2d(float **arr, int rows, int cols)
{
    // arr[i][j] -> flat[i * cols + j]
    float *flat = (float*) malloc(rows * cols * sizeof(float));
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            flat[i * cols + j] = arr[i][j];
        }
    }
    return flat;
}

static void unflatten_2d(float *flat, float **arr, int rows, int cols)
{
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            arr[i][j] = flat[i * cols + j];
        }
    }
}

////////////////////////////////////////////////////////////////////////////////
// Program main
////////////////////////////////////////////////////////////////////////////////
int main(int argc, char** argv)
{
    setup(argc, argv);
    return 0;
}


void bpnn_train_kernel(BPNN *net, float *eo, float *eh)
{
    int in, hid, out;
    float out_err, hid_err;

    in  = net->input_n;
    hid = net->hidden_n;
    out = net->output_n;

    // Dimensions:
    // input_weights:       (in+1) x (hid+1)
    // hidden_weights:      (hid+1) x (out+1)
    // input_prev_weights:  (in+1) x (hid+1)
    // hidden_prev_weights: (hid+1) x (out+1)

    int iw_rows = in + 1,  iw_cols = hid + 1;
    int hw_rows = hid + 1, hw_cols = out + 1;

    // Flatten weight matrices
    float *iw_flat  = flatten_2d(net->input_weights,       iw_rows, iw_cols);
    float *hw_flat  = flatten_2d(net->hidden_weights,      hw_rows, hw_cols);
    float *ipw_flat = flatten_2d(net->input_prev_weights,  iw_rows, iw_cols);
    float *hpw_flat = flatten_2d(net->hidden_prev_weights, hw_rows, hw_cols);

    // Device pointers
    float *d_input_units, *d_hidden_units, *d_output_units;
    float *d_iw_flat, *d_hw_flat, *d_ipw_flat, *d_hpw_flat;
    float *d_hidden_delta, *d_output_delta, *d_target;

    // Allocate device memory
    cudaMalloc((void**)&d_input_units,  (in + 1)  * sizeof(float));
    cudaMalloc((void**)&d_hidden_units, (hid + 1) * sizeof(float));
    cudaMalloc((void**)&d_output_units, (out + 1) * sizeof(float));
    cudaMalloc((void**)&d_hidden_delta, (hid + 1) * sizeof(float));
    cudaMalloc((void**)&d_output_delta, (out + 1) * sizeof(float));
    cudaMalloc((void**)&d_target,       (out + 1) * sizeof(float));
    cudaMalloc((void**)&d_iw_flat,  iw_rows * iw_cols * sizeof(float));
    cudaMalloc((void**)&d_hw_flat,  hw_rows * hw_cols * sizeof(float));
    cudaMalloc((void**)&d_ipw_flat, iw_rows * iw_cols * sizeof(float));
    cudaMalloc((void**)&d_hpw_flat, hw_rows * hw_cols * sizeof(float));

    // Copy data to device
    cudaMemcpy(d_input_units,  net->input_units,  (in + 1)  * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(d_hidden_units, net->hidden_units, (hid + 1) * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(d_output_units, net->output_units, (out + 1) * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(d_hidden_delta, net->hidden_delta, (hid + 1) * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(d_output_delta, net->output_delta, (out + 1) * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(d_target,       net->target,       (out + 1) * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(d_iw_flat,  iw_flat,  iw_rows * iw_cols * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(d_hw_flat,  hw_flat,  hw_rows * hw_cols * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(d_ipw_flat, ipw_flat, iw_rows * iw_cols * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(d_hpw_flat, hpw_flat, hw_rows * hw_cols * sizeof(float), cudaMemcpyHostToDevice);

    printf("Performing GPU computation\n");

    // Set input threshold unit l1[0] = 1.0
    float one = 1.0f;
    cudaMemcpy(d_input_units, &one, sizeof(float), cudaMemcpyHostToDevice);

    // ---- bpnn_layerforward: input -> hidden ----
    {
        int threads = THREADS;
        int blocks = (hid + threads - 1) / threads;
        bpnn_layerforward_cuda<<<blocks, threads>>>(d_input_units, d_hidden_units, d_iw_flat, in, hid);
        cudaDeviceSynchronize();
    }

    // Set hidden threshold unit l1[0] = 1.0
    cudaMemcpy(d_hidden_units, &one, sizeof(float), cudaMemcpyHostToDevice);

    // ---- bpnn_layerforward: hidden -> output ----
    {
        int threads = THREADS;
        int blocks = (out + threads - 1) / threads;
        bpnn_layerforward_cuda<<<blocks, threads>>>(d_hidden_units, d_output_units, d_hw_flat, hid, out);
        cudaDeviceSynchronize();
    }

    // Copy results back for CPU error computation
    cudaMemcpy(net->hidden_units, d_hidden_units, (hid + 1) * sizeof(float), cudaMemcpyDeviceToHost);
    cudaMemcpy(net->output_units, d_output_units, (out + 1) * sizeof(float), cudaMemcpyDeviceToHost);

    // ---- bpnn_output_error (CPU) ----
    bpnn_output_error(net->output_delta, net->target, net->output_units, out, &out_err);

    // ---- bpnn_hidden_error (CPU) ----
    // Unflatten hidden_weights for CPU use
    unflatten_2d(hw_flat, net->hidden_weights, hw_rows, hw_cols);
    bpnn_hidden_error(net->hidden_delta, hid, net->output_delta, out,
                      net->hidden_weights, net->hidden_units, &hid_err);

    *eo = out_err;
    *eh = hid_err;

    // Copy updated deltas to device
    cudaMemcpy(d_output_delta, net->output_delta, (out + 1) * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(d_hidden_delta, net->hidden_delta, (hid + 1) * sizeof(float), cudaMemcpyHostToDevice);

    // Set ly[0] = 1.0 for hidden_units (threshold unit for adjust_weights on output layer)
    cudaMemcpy(d_hidden_units, &one, sizeof(float), cudaMemcpyHostToDevice);

    // ---- bpnn_adjust_weights: output_delta, hidden_units -> hidden_weights ----
    // ndelta=out, nly=hid, w=(hid+1)x(out+1)
    {
        dim3 threads(16, 16);
        dim3 blocks((out + 15) / 16, (hid + 1 + 15) / 16);
        bpnn_adjust_weights_cuda<<<blocks, threads>>>(d_output_delta, out, d_hidden_units, hid,
                                                       d_hw_flat, d_hpw_flat);
        cudaDeviceSynchronize();
    }

    // Set ly[0] = 1.0 for input_units (threshold unit for adjust_weights on input layer)
    cudaMemcpy(d_input_units, &one, sizeof(float), cudaMemcpyHostToDevice);

    // ---- bpnn_adjust_weights: hidden_delta, input_units -> input_weights ----
    // ndelta=hid, nly=in, w=(in+1)x(hid+1)
    {
        dim3 threads(16, 16);
        dim3 blocks((hid + 15) / 16, (in + 1 + 15) / 16);
        bpnn_adjust_weights_cuda<<<blocks, threads>>>(d_hidden_delta, hid, d_input_units, in,
                                                       d_iw_flat, d_ipw_flat);
        cudaDeviceSynchronize();
    }

    // Copy results back to host
    cudaMemcpy(net->input_units,  d_input_units,  (in + 1)  * sizeof(float), cudaMemcpyDeviceToHost);
    cudaMemcpy(net->hidden_units, d_hidden_units, (hid + 1) * sizeof(float), cudaMemcpyDeviceToHost);
    cudaMemcpy(net->output_units, d_output_units, (out + 1) * sizeof(float), cudaMemcpyDeviceToHost);
    cudaMemcpy(iw_flat,  d_iw_flat,  iw_rows * iw_cols * sizeof(float), cudaMemcpyDeviceToHost);
    cudaMemcpy(hw_flat,  d_hw_flat,  hw_rows * hw_cols * sizeof(float), cudaMemcpyDeviceToHost);
    cudaMemcpy(ipw_flat, d_ipw_flat, iw_rows * iw_cols * sizeof(float), cudaMemcpyDeviceToHost);
    cudaMemcpy(hpw_flat, d_hpw_flat, hw_rows * hw_cols * sizeof(float), cudaMemcpyDeviceToHost);

    // Unflatten weight matrices back to 2D
    unflatten_2d(iw_flat,  net->input_weights,       iw_rows, iw_cols);
    unflatten_2d(hw_flat,  net->hidden_weights,      hw_rows, hw_cols);
    unflatten_2d(ipw_flat, net->input_prev_weights,  iw_rows, iw_cols);
    unflatten_2d(hpw_flat, net->hidden_prev_weights, hw_rows, hw_cols);

    // Free device memory
    cudaFree(d_input_units);
    cudaFree(d_hidden_units);
    cudaFree(d_output_units);
    cudaFree(d_hidden_delta);
    cudaFree(d_output_delta);
    cudaFree(d_target);
    cudaFree(d_iw_flat);
    cudaFree(d_hw_flat);
    cudaFree(d_ipw_flat);
    cudaFree(d_hpw_flat);

    // Free host flat arrays
    free(iw_flat);
    free(hw_flat);
    free(ipw_flat);
    free(hpw_flat);
}

