// Copyright 2009, Andrew Corrigan, acorriga@gmu.edu
// This code is from the AIAA-2009-4001 paper

#include <iostream>
#include <fstream>
#include <cmath>
#include <cuda.h>
#include <cuda_runtime.h>

#ifndef block_length
#define block_length 128
#endif

#define GAMMA 1.4
#define iterations 2000

#define NDIM 3
#define NNB 4

#define RK 3
#define ff_mach 1.2
#define deg_angle_of_attack 0.0

#define VAR_DENSITY 0
#define VAR_MOMENTUM  1
#define VAR_DENSITY_ENERGY (VAR_MOMENTUM+NDIM)
#define NVAR (VAR_DENSITY_ENERGY+1)

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 192
#endif

struct double3_t { double x, y, z; };

#define CUDA_SAFE_CALL(call) \
do { \
    cudaError_t err = call; \
    if(err != cudaSuccess) { \
        fprintf(stderr, "CUDA error at %s:%d: %s\n", __FILE__, __LINE__, cudaGetErrorString(err)); \
        exit(EXIT_FAILURE); \
    } \
} while(0)

__device__ __host__ inline void compute_velocity(double density, double3_t momentum, double3_t& velocity)
{
    velocity.x = momentum.x / density;
    velocity.y = momentum.y / density;
    velocity.z = momentum.z / density;
}

__device__ __host__ inline double compute_speed_sqd(double3_t velocity)
{
    return velocity.x*velocity.x + velocity.y*velocity.y + velocity.z*velocity.z;
}

__device__ __host__ inline double compute_pressure(double density, double density_energy, double speed_sqd)
{
    return (double(GAMMA)-double(1.0))*(density_energy - double(0.5)*density*speed_sqd);
}

__device__ __host__ inline double compute_speed_of_sound(double density, double pressure)
{
    return sqrt(double(GAMMA)*pressure/density);
}

__device__ __host__ inline void compute_flux_contribution(double density, double3_t momentum, double density_energy,
    double pressure, double3_t velocity,
    double3_t& fc_momentum_x, double3_t& fc_momentum_y, double3_t& fc_momentum_z,
    double3_t& fc_density_energy)
{
    fc_momentum_x.x = velocity.x*momentum.x + pressure;
    fc_momentum_x.y = velocity.x*momentum.y;
    fc_momentum_x.z = velocity.x*momentum.z;

    fc_momentum_y.x = fc_momentum_x.y;
    fc_momentum_y.y = velocity.y*momentum.y + pressure;
    fc_momentum_y.z = velocity.y*momentum.z;

    fc_momentum_z.x = fc_momentum_x.z;
    fc_momentum_z.y = fc_momentum_y.z;
    fc_momentum_z.z = velocity.z*momentum.z + pressure;

    double de_p = density_energy + pressure;
    fc_density_energy.x = velocity.x*de_p;
    fc_density_energy.y = velocity.y*de_p;
    fc_density_energy.z = velocity.z*de_p;
}

__global__ void cuda_initialize_variables(int nelr, double* variables, double* ff_variable)
{
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if(i < nelr)
    {
        for(int j = 0; j < NVAR; j++)
            variables[i*NVAR + j] = ff_variable[j];
    }
}

__global__ void cuda_copy(double* dst, double* src, int N)
{
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if(i < N)
        dst[i] = src[i];
}

__global__ void cuda_compute_step_factor(int nelr, double* variables, double* areas, double* step_factors)
{
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if(i >= nelr) return;

    double density = variables[NVAR*i + VAR_DENSITY];

    double3_t momentum;
    momentum.x = variables[NVAR*i + (VAR_MOMENTUM+0)];
    momentum.y = variables[NVAR*i + (VAR_MOMENTUM+1)];
    momentum.z = variables[NVAR*i + (VAR_MOMENTUM+2)];

    double density_energy = variables[NVAR*i + VAR_DENSITY_ENERGY];

    double3_t velocity;
    compute_velocity(density, momentum, velocity);
    double speed_sqd      = compute_speed_sqd(velocity);
    double pressure       = compute_pressure(density, density_energy, speed_sqd);
    double speed_of_sound = compute_speed_of_sound(density, pressure);

    step_factors[i] = double(0.5) / (sqrt(areas[i]) * (sqrt(speed_sqd) + speed_of_sound));
}

__global__ void cuda_compute_flux(int nelr, int* elements_surrounding_elements, double* normals,
    double* variables, double* fluxes,
    double* ff_variable,
    double3_t ff_flux_contribution_momentum_x,
    double3_t ff_flux_contribution_momentum_y,
    double3_t ff_flux_contribution_momentum_z,
    double3_t ff_flux_contribution_density_energy)
{
    const double smoothing_coefficient = double(0.2f);
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if(i >= nelr) return;

    double density_i = variables[NVAR*i + VAR_DENSITY];
    double3_t momentum_i;
    momentum_i.x = variables[NVAR*i + (VAR_MOMENTUM+0)];
    momentum_i.y = variables[NVAR*i + (VAR_MOMENTUM+1)];
    momentum_i.z = variables[NVAR*i + (VAR_MOMENTUM+2)];

    double density_energy_i = variables[NVAR*i + VAR_DENSITY_ENERGY];

    double3_t velocity_i;
    compute_velocity(density_i, momentum_i, velocity_i);
    double speed_sqd_i       = compute_speed_sqd(velocity_i);
    double speed_i           = sqrt(speed_sqd_i);
    double pressure_i        = compute_pressure(density_i, density_energy_i, speed_sqd_i);
    double speed_of_sound_i  = compute_speed_of_sound(density_i, pressure_i);

    double3_t flux_contribution_i_momentum_x, flux_contribution_i_momentum_y, flux_contribution_i_momentum_z;
    double3_t flux_contribution_i_density_energy;
    compute_flux_contribution(density_i, momentum_i, density_energy_i, pressure_i, velocity_i,
        flux_contribution_i_momentum_x, flux_contribution_i_momentum_y, flux_contribution_i_momentum_z,
        flux_contribution_i_density_energy);

    double flux_i_density = double(0.0);
    double3_t flux_i_momentum;
    flux_i_momentum.x = double(0.0);
    flux_i_momentum.y = double(0.0);
    flux_i_momentum.z = double(0.0);
    double flux_i_density_energy = double(0.0);

    for(int j = 0; j < NNB; j++)
    {
        double3_t normal;
        double normal_len;
        double factor;

        int nb = elements_surrounding_elements[i*NNB + j];
        normal.x = normals[(i*NNB + j)*NDIM + 0];
        normal.y = normals[(i*NNB + j)*NDIM + 1];
        normal.z = normals[(i*NNB + j)*NDIM + 2];
        normal_len = sqrt(normal.x*normal.x + normal.y*normal.y + normal.z*normal.z);

        if(nb >= 0)
        {
            double density_nb        = variables[nb*NVAR + VAR_DENSITY];
            double3_t momentum_nb;
            momentum_nb.x            = variables[nb*NVAR + (VAR_MOMENTUM+0)];
            momentum_nb.y            = variables[nb*NVAR + (VAR_MOMENTUM+1)];
            momentum_nb.z            = variables[nb*NVAR + (VAR_MOMENTUM+2)];
            double density_energy_nb = variables[nb*NVAR + VAR_DENSITY_ENERGY];

            double3_t velocity_nb;
            compute_velocity(density_nb, momentum_nb, velocity_nb);
            double speed_sqd_nb      = compute_speed_sqd(velocity_nb);
            double pressure_nb       = compute_pressure(density_nb, density_energy_nb, speed_sqd_nb);
            double speed_of_sound_nb = compute_speed_of_sound(density_nb, pressure_nb);

            double3_t flux_contribution_nb_momentum_x, flux_contribution_nb_momentum_y, flux_contribution_nb_momentum_z;
            double3_t flux_contribution_nb_density_energy;
            compute_flux_contribution(density_nb, momentum_nb, density_energy_nb, pressure_nb, velocity_nb,
                flux_contribution_nb_momentum_x, flux_contribution_nb_momentum_y, flux_contribution_nb_momentum_z,
                flux_contribution_nb_density_energy);

            factor = -normal_len*smoothing_coefficient*double(0.5)*(speed_i + sqrt(speed_sqd_nb) + speed_of_sound_i + speed_of_sound_nb);
            flux_i_density          += factor*(density_i-density_nb);
            flux_i_density_energy   += factor*(density_energy_i-density_energy_nb);
            flux_i_momentum.x       += factor*(momentum_i.x-momentum_nb.x);
            flux_i_momentum.y       += factor*(momentum_i.y-momentum_nb.y);
            flux_i_momentum.z       += factor*(momentum_i.z-momentum_nb.z);

            factor = double(0.5)*normal.x;
            flux_i_density          += factor*(momentum_nb.x+momentum_i.x);
            flux_i_density_energy   += factor*(flux_contribution_nb_density_energy.x+flux_contribution_i_density_energy.x);
            flux_i_momentum.x       += factor*(flux_contribution_nb_momentum_x.x+flux_contribution_i_momentum_x.x);
            flux_i_momentum.y       += factor*(flux_contribution_nb_momentum_y.x+flux_contribution_i_momentum_y.x);
            flux_i_momentum.z       += factor*(flux_contribution_nb_momentum_z.x+flux_contribution_i_momentum_z.x);

            factor = double(0.5)*normal.y;
            flux_i_density          += factor*(momentum_nb.y+momentum_i.y);
            flux_i_density_energy   += factor*(flux_contribution_nb_density_energy.y+flux_contribution_i_density_energy.y);
            flux_i_momentum.x       += factor*(flux_contribution_nb_momentum_x.y+flux_contribution_i_momentum_x.y);
            flux_i_momentum.y       += factor*(flux_contribution_nb_momentum_y.y+flux_contribution_i_momentum_y.y);
            flux_i_momentum.z       += factor*(flux_contribution_nb_momentum_z.y+flux_contribution_i_momentum_z.y);

            factor = double(0.5)*normal.z;
            flux_i_density          += factor*(momentum_nb.z+momentum_i.z);
            flux_i_density_energy   += factor*(flux_contribution_nb_density_energy.z+flux_contribution_i_density_energy.z);
            flux_i_momentum.x       += factor*(flux_contribution_nb_momentum_x.z+flux_contribution_i_momentum_x.z);
            flux_i_momentum.y       += factor*(flux_contribution_nb_momentum_y.z+flux_contribution_i_momentum_y.z);
            flux_i_momentum.z       += factor*(flux_contribution_nb_momentum_z.z+flux_contribution_i_momentum_z.z);
        }
        else if(nb == -1)
        {
            flux_i_momentum.x += normal.x*pressure_i;
            flux_i_momentum.y += normal.y*pressure_i;
            flux_i_momentum.z += normal.z*pressure_i;
        }
        else if(nb == -2)
        {
            factor = double(0.5)*normal.x;
            flux_i_density          += factor*(ff_variable[VAR_MOMENTUM+0]+momentum_i.x);
            flux_i_density_energy   += factor*(ff_flux_contribution_density_energy.x+flux_contribution_i_density_energy.x);
            flux_i_momentum.x       += factor*(ff_flux_contribution_momentum_x.x + flux_contribution_i_momentum_x.x);
            flux_i_momentum.y       += factor*(ff_flux_contribution_momentum_y.x + flux_contribution_i_momentum_y.x);
            flux_i_momentum.z       += factor*(ff_flux_contribution_momentum_z.x + flux_contribution_i_momentum_z.x);

            factor = double(0.5)*normal.y;
            flux_i_density          += factor*(ff_variable[VAR_MOMENTUM+1]+momentum_i.y);
            flux_i_density_energy   += factor*(ff_flux_contribution_density_energy.y+flux_contribution_i_density_energy.y);
            flux_i_momentum.x       += factor*(ff_flux_contribution_momentum_x.y + flux_contribution_i_momentum_x.y);
            flux_i_momentum.y       += factor*(ff_flux_contribution_momentum_y.y + flux_contribution_i_momentum_y.y);
            flux_i_momentum.z       += factor*(ff_flux_contribution_momentum_z.y + flux_contribution_i_momentum_z.y);

            factor = double(0.5)*normal.z;
            flux_i_density          += factor*(ff_variable[VAR_MOMENTUM+2]+momentum_i.z);
            flux_i_density_energy   += factor*(ff_flux_contribution_density_energy.z+flux_contribution_i_density_energy.z);
            flux_i_momentum.x       += factor*(ff_flux_contribution_momentum_x.z + flux_contribution_i_momentum_x.z);
            flux_i_momentum.y       += factor*(ff_flux_contribution_momentum_y.z + flux_contribution_i_momentum_y.z);
            flux_i_momentum.z       += factor*(ff_flux_contribution_momentum_z.z + flux_contribution_i_momentum_z.z);
        }
    }

    fluxes[NVAR*i + VAR_DENSITY]        = flux_i_density;
    fluxes[NVAR*i + (VAR_MOMENTUM+0)]   = flux_i_momentum.x;
    fluxes[NVAR*i + (VAR_MOMENTUM+1)]   = flux_i_momentum.y;
    fluxes[NVAR*i + (VAR_MOMENTUM+2)]   = flux_i_momentum.z;
    fluxes[NVAR*i + VAR_DENSITY_ENERGY] = flux_i_density_energy;
}

__global__ void cuda_time_step(int j, int nelr, double* old_variables, double* variables, double* step_factors, double* fluxes)
{
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if(i >= nelr) return;

    double factor = step_factors[i]/double(RK+1-j);

    variables[NVAR*i + VAR_DENSITY]        = old_variables[NVAR*i + VAR_DENSITY]        + factor*fluxes[NVAR*i + VAR_DENSITY];
    variables[NVAR*i + VAR_DENSITY_ENERGY] = old_variables[NVAR*i + VAR_DENSITY_ENERGY] + factor*fluxes[NVAR*i + VAR_DENSITY_ENERGY];
    variables[NVAR*i + (VAR_MOMENTUM+0)]   = old_variables[NVAR*i + (VAR_MOMENTUM+0)]   + factor*fluxes[NVAR*i + (VAR_MOMENTUM+0)];
    variables[NVAR*i + (VAR_MOMENTUM+1)]   = old_variables[NVAR*i + (VAR_MOMENTUM+1)]   + factor*fluxes[NVAR*i + (VAR_MOMENTUM+1)];
    variables[NVAR*i + (VAR_MOMENTUM+2)]   = old_variables[NVAR*i + (VAR_MOMENTUM+2)]   + factor*fluxes[NVAR*i + (VAR_MOMENTUM+2)];
}

void dump(double* variables, int nel, int nelr)
{
    {
        std::ofstream file("density");
        file << nel << " " << nelr << std::endl;
        for(int i = 0; i < nel; i++) file << variables[i*NVAR + VAR_DENSITY] << std::endl;
    }
    {
        std::ofstream file("momentum");
        file << nel << " " << nelr << std::endl;
        for(int i = 0; i < nel; i++)
        {
            for(int j = 0; j != NDIM; j++) file << variables[i*NVAR + (VAR_MOMENTUM+j)] << " ";
            file << std::endl;
        }
    }
    {
        std::ofstream file("density_energy");
        file << nel << " " << nelr << std::endl;
        for(int i = 0; i < nel; i++) file << variables[i*NVAR + VAR_DENSITY_ENERGY] << std::endl;
    }
}

int main(int argc, char** argv)
{
    if(argc < 2)
    {
        std::cout << "specify data file name" << std::endl;
        return 0;
    }
    const char* data_file_name = argv[1];

    double ff_variable[NVAR];
    double3_t ff_flux_contribution_momentum_x, ff_flux_contribution_momentum_y,
              ff_flux_contribution_momentum_z, ff_flux_contribution_density_energy;

    {
        const double angle_of_attack = double(3.1415926535897931 / 180.0) * double(deg_angle_of_attack);

        ff_variable[VAR_DENSITY] = double(1.4);

        double ff_pressure = double(1.0);
        double ff_speed_of_sound = sqrt(GAMMA*ff_pressure / ff_variable[VAR_DENSITY]);
        double ff_speed = double(ff_mach)*ff_speed_of_sound;

        double3_t ff_velocity;
        ff_velocity.x = ff_speed*double(cos((double)angle_of_attack));
        ff_velocity.y = ff_speed*double(sin((double)angle_of_attack));
        ff_velocity.z = 0.0;

        ff_variable[VAR_MOMENTUM+0] = ff_variable[VAR_DENSITY] * ff_velocity.x;
        ff_variable[VAR_MOMENTUM+1] = ff_variable[VAR_DENSITY] * ff_velocity.y;
        ff_variable[VAR_MOMENTUM+2] = ff_variable[VAR_DENSITY] * ff_velocity.z;

        ff_variable[VAR_DENSITY_ENERGY] = ff_variable[VAR_DENSITY]*(double(0.5)*(ff_speed*ff_speed)) + (ff_pressure / double(GAMMA-1.0));

        double3_t ff_momentum;
        ff_momentum.x = *(ff_variable+VAR_MOMENTUM+0);
        ff_momentum.y = *(ff_variable+VAR_MOMENTUM+1);
        ff_momentum.z = *(ff_variable+VAR_MOMENTUM+2);
        compute_flux_contribution(ff_variable[VAR_DENSITY], ff_momentum, ff_variable[VAR_DENSITY_ENERGY],
            ff_pressure, ff_velocity,
            ff_flux_contribution_momentum_x, ff_flux_contribution_momentum_y,
            ff_flux_contribution_momentum_z, ff_flux_contribution_density_energy);
    }

    int nel;
    int nelr;

    double* areas;
    int* elements_surrounding_elements;
    double* normals;

    {
        std::ifstream file(data_file_name);
        file >> nel;
        nelr = block_length*((nel / block_length) + std::min(1, nel % block_length));

        areas = new double[nelr];
        elements_surrounding_elements = new int[nelr*NNB];
        normals = new double[NDIM*NNB*nelr];

        for(int i = 0; i < nel; i++)
        {
            file >> areas[i];
            for(int j = 0; j < NNB; j++)
            {
                file >> elements_surrounding_elements[i*NNB + j];
                if(elements_surrounding_elements[i*NNB+j] < 0) elements_surrounding_elements[i*NNB+j] = -1;
                elements_surrounding_elements[i*NNB + j]--;

                for(int k = 0; k < NDIM; k++)
                {
                    file >> normals[(i*NNB + j)*NDIM + k];
                    normals[(i*NNB + j)*NDIM + k] = -normals[(i*NNB + j)*NDIM + k];
                }
            }
        }

        int last = nel-1;
        for(int i = nel; i < nelr; i++)
        {
            areas[i] = areas[last];
            for(int j = 0; j < NNB; j++)
            {
                elements_surrounding_elements[i*NNB + j] = elements_surrounding_elements[last*NNB + j];
                for(int k = 0; k < NDIM; k++) normals[(i*NNB + j)*NDIM + k] = normals[(last*NNB + j)*NDIM + k];
            }
        }
    }

    double *d_areas, *d_variables, *d_old_variables, *d_fluxes, *d_step_factors;
    int *d_elements_surrounding_elements;
    double *d_normals;
    double *d_ff_variable;

    CUDA_SAFE_CALL(cudaMalloc(&d_areas, nelr*sizeof(double)));
    CUDA_SAFE_CALL(cudaMalloc(&d_variables, nelr*NVAR*sizeof(double)));
    CUDA_SAFE_CALL(cudaMalloc(&d_old_variables, nelr*NVAR*sizeof(double)));
    CUDA_SAFE_CALL(cudaMalloc(&d_fluxes, nelr*NVAR*sizeof(double)));
    CUDA_SAFE_CALL(cudaMalloc(&d_step_factors, nelr*sizeof(double)));
    CUDA_SAFE_CALL(cudaMalloc(&d_elements_surrounding_elements, nelr*NNB*sizeof(int)));
    CUDA_SAFE_CALL(cudaMalloc(&d_normals, NDIM*NNB*nelr*sizeof(double)));
    CUDA_SAFE_CALL(cudaMalloc(&d_ff_variable, NVAR*sizeof(double)));

    CUDA_SAFE_CALL(cudaMemcpy(d_areas, areas, nelr*sizeof(double), cudaMemcpyHostToDevice));
    CUDA_SAFE_CALL(cudaMemcpy(d_elements_surrounding_elements, elements_surrounding_elements, nelr*NNB*sizeof(int), cudaMemcpyHostToDevice));
    CUDA_SAFE_CALL(cudaMemcpy(d_normals, normals, NDIM*NNB*nelr*sizeof(double), cudaMemcpyHostToDevice));
    CUDA_SAFE_CALL(cudaMemcpy(d_ff_variable, ff_variable, NVAR*sizeof(double), cudaMemcpyHostToDevice));

    int blocks = (nelr + BLOCK_SIZE - 1) / BLOCK_SIZE;

    cuda_initialize_variables<<<blocks, BLOCK_SIZE>>>(nelr, d_variables, d_ff_variable);
    CUDA_SAFE_CALL(cudaGetLastError());

    std::cout << "Starting..." << std::endl;

    cudaEvent_t start_event, stop_event;
    CUDA_SAFE_CALL(cudaEventCreate(&start_event));
    CUDA_SAFE_CALL(cudaEventCreate(&stop_event));
    CUDA_SAFE_CALL(cudaEventRecord(start_event, 0));

    for(int i = 0; i < iterations; i++)
    {
        cuda_copy<<<(nelr*NVAR + BLOCK_SIZE - 1)/BLOCK_SIZE, BLOCK_SIZE>>>(d_old_variables, d_variables, nelr*NVAR);

        cuda_compute_step_factor<<<blocks, BLOCK_SIZE>>>(nelr, d_variables, d_areas, d_step_factors);

        for(int j = 0; j < RK; j++)
        {
            cuda_compute_flux<<<blocks, BLOCK_SIZE>>>(nelr, d_elements_surrounding_elements, d_normals,
                d_variables, d_fluxes, d_ff_variable,
                ff_flux_contribution_momentum_x, ff_flux_contribution_momentum_y,
                ff_flux_contribution_momentum_z, ff_flux_contribution_density_energy);

            cuda_time_step<<<blocks, BLOCK_SIZE>>>(j, nelr, d_old_variables, d_variables, d_step_factors, d_fluxes);
        }
    }

    CUDA_SAFE_CALL(cudaEventRecord(stop_event, 0));
    CUDA_SAFE_CALL(cudaEventSynchronize(stop_event));
    float elapsed;
    CUDA_SAFE_CALL(cudaEventElapsedTime(&elapsed, start_event, stop_event));
    std::cout << elapsed/1000.0/iterations << " seconds per iteration" << std::endl;

    double* h_variables = new double[nelr*NVAR];
    CUDA_SAFE_CALL(cudaMemcpy(h_variables, d_variables, nelr*NVAR*sizeof(double), cudaMemcpyDeviceToHost));

    std::cout << "Saving solution..." << std::endl;
    dump(h_variables, nel, nelr);
    std::cout << "Saved solution..." << std::endl;

    std::cout << "Cleaning up..." << std::endl;
    delete[] areas;
    delete[] elements_surrounding_elements;
    delete[] normals;
    delete[] h_variables;

    cudaFree(d_areas);
    cudaFree(d_variables);
    cudaFree(d_old_variables);
    cudaFree(d_fluxes);
    cudaFree(d_step_factors);
    cudaFree(d_elements_surrounding_elements);
    cudaFree(d_normals);
    cudaFree(d_ff_variable);

    cudaEventDestroy(start_event);
    cudaEventDestroy(stop_event);

    std::cout << "Done..." << std::endl;
    return 0;
}

