	// POINT MASK
	pub.mask_rows = pub.maxMove;
	pub.mask_cols = pub.mask_rows;
	pub.mask_elem = pub.mask_rows * pub.mask_cols;
	pub.mask_mem = sizeof(fp) * pub.mask_elem;

	// MASK CONVOLUTION
	pub.mask_conv_rows = pub.tMask_rows;
	pub.mask_conv_cols = pub.tMask_cols;
	pub.mask_conv_elem = pub.mask_conv_rows * pub.mask_conv_cols;
	pub.mask_conv_mem = sizeof(fp) * pub.mask_conv_elem;
	pub.mask_conv_ioffset = (pub.mask_rows - 1) / 2;
	if((pub.mask_rows - 1) % 2 > 0.5){
		pub.mask_conv_ioffset = pub.mask_conv_ioffset + 1;
	}
	pub.mask_conv_joffset = (pub.mask_cols - 1) / 2;
	if((pub.mask_cols - 1) % 2 > 0.5){
		pub.mask_conv_joffset = pub.mask_conv_joffset + 1;
	}

	// Allocate GPU memory for shared arrays
	int* gpu_endoRow;
	int* gpu_endoCol;
	int* gpu_tEndoRowLoc;
	int* gpu_tEndoColLoc;
	fp*  gpu_endoT;

	int* gpu_epiRow;
	int* gpu_epiCol;
	int* gpu_tEpiRowLoc;
	int* gpu_tEpiColLoc;
	fp*  gpu_epiT;

	cudaMalloc((void**)&gpu_endoRow, pub.d_endo_mem);
	cudaMalloc((void**)&gpu_endoCol, pub.d_endo_mem);
	cudaMalloc((void**)&gpu_tEndoRowLoc, pub.d_endo_mem * pub.frames);
	cudaMalloc((void**)&gpu_tEndoColLoc, pub.d_endo_mem * pub.frames);
	cudaMalloc((void**)&gpu_endoT, pub.in_mod_mem * pub.endoPoints);

	cudaMalloc((void**)&gpu_epiRow, pub.d_epi_mem);
	cudaMalloc((void**)&gpu_epiCol, pub.d_epi_mem);
	cudaMalloc((void**)&gpu_tEpiRowLoc, pub.d_epi_mem * pub.frames);
	cudaMalloc((void**)&gpu_tEpiColLoc, pub.d_epi_mem * pub.frames);
	cudaMalloc((void**)&gpu_epiT, pub.in_mod_mem * pub.epiPoints);

	cudaMemcpy(gpu_endoRow, h_endoRow, pub.d_endo_mem, cudaMemcpyHostToDevice);
	cudaMemcpy(gpu_endoCol, h_endoCol, pub.d_endo_mem, cudaMemcpyHostToDevice);
	cudaMemcpy(gpu_epiRow, h_epiRow, pub.d_epi_mem, cudaMemcpyHostToDevice);
	cudaMemcpy(gpu_epiCol, h_epiCol, pub.d_epi_mem, cudaMemcpyHostToDevice);

	// Set pub pointers to GPU memory
	pub.d_endoRow = gpu_endoRow;
	pub.d_endoCol = gpu_endoCol;
	pub.d_tEndoRowLoc = gpu_tEndoRowLoc;
	pub.d_tEndoColLoc = gpu_tEndoColLoc;
	pub.d_endoT = gpu_endoT;

	pub.d_epiRow = gpu_epiRow;
	pub.d_epiCol = gpu_epiCol;
	pub.d_tEpiRowLoc = gpu_tEpiRowLoc;
	pub.d_tEpiColLoc = gpu_tEpiColLoc;
	pub.d_epiT = gpu_epiT;

	// Allocate per-point GPU arrays
	fp** gpu_in2 = (fp**)malloc(ALL_POINTS * sizeof(fp*));
	fp** gpu_in2_sqr = (fp**)malloc(ALL_POINTS * sizeof(fp*));
	fp** gpu_in_mod = (fp**)malloc(ALL_POINTS * sizeof(fp*));
	fp** gpu_in_sqr = (fp**)malloc(ALL_POINTS * sizeof(fp*));
	fp** gpu_conv = (fp**)malloc(ALL_POINTS * sizeof(fp*));
	fp** gpu_in2_pad = (fp**)malloc(ALL_POINTS * sizeof(fp*));
	fp** gpu_in2_sub = (fp**)malloc(ALL_POINTS * sizeof(fp*));
	fp** gpu_in2_sub2_sqr = (fp**)malloc(ALL_POINTS * sizeof(fp*));
	fp** gpu_tMask = (fp**)malloc(ALL_POINTS * sizeof(fp*));
	fp** gpu_mask_conv = (fp**)malloc(ALL_POINTS * sizeof(fp*));
	fp** gpu_in_partial_sum = (fp**)malloc(ALL_POINTS * sizeof(fp*));
	fp** gpu_in_sqr_partial_sum = (fp**)malloc(ALL_POINTS * sizeof(fp*));
	fp** gpu_par_max_val = (fp**)malloc(ALL_POINTS * sizeof(fp*));
	int** gpu_par_max_coo = (int**)malloc(ALL_POINTS * sizeof(int*));

	for(i=0; i<ALL_POINTS; i++){
		cudaMalloc((void**)&gpu_in2[i], pub.in2_mem);
		cudaMalloc((void**)&gpu_in2_sqr[i], pub.in2_mem);
		cudaMalloc((void**)&gpu_in_mod[i], pub.in_mod_mem);
		cudaMalloc((void**)&gpu_in_sqr[i], pub.in_mod_mem);
		cudaMalloc((void**)&gpu_conv[i], pub.conv_mem);
		cudaMalloc((void**)&gpu_in2_pad[i], pub.in2_pad_mem);
		cudaMalloc((void**)&gpu_in2_sub[i], pub.in2_sub_mem);
		cudaMalloc((void**)&gpu_in2_sub2_sqr[i], pub.in2_sub2_sqr_mem);
		cudaMalloc((void**)&gpu_tMask[i], pub.tMask_mem);
		cudaMalloc((void**)&gpu_mask_conv[i], pub.mask_conv_mem);
		cudaMalloc((void**)&gpu_in_partial_sum[i], sizeof(fp) * (2*pub.tSize+1));
		cudaMalloc((void**)&gpu_in_sqr_partial_sum[i], sizeof(fp) * (2*pub.tSize+1));
		cudaMalloc((void**)&gpu_par_max_val[i], sizeof(fp) * (2*pub.tSize+2*pub.sSize+1));
		cudaMalloc((void**)&gpu_par_max_coo[i], sizeof(int) * (2*pub.tSize+2*pub.sSize+1));
	}

	// Setup host private structs
	for(i=0; i<pub.endoPoints; i++){
		h_priv[i].point_no = i;
		h_priv[i].in_pointer = i * pub.in_mod_elem;
		h_priv[i].d_Row = gpu_endoRow;
		h_priv[i].d_Col = gpu_endoCol;
		h_priv[i].d_tRowLoc = gpu_tEndoRowLoc;
		h_priv[i].d_tColLoc = gpu_tEndoColLoc;
		h_priv[i].d_T = gpu_endoT;
		h_priv[i].d_in2 = gpu_in2[i];
		h_priv[i].d_in2_sqr = gpu_in2_sqr[i];
		h_priv[i].d_in_mod = gpu_in_mod[i];
		h_priv[i].d_in_sqr = gpu_in_sqr[i];
		h_priv[i].d_conv = gpu_conv[i];
		h_priv[i].d_in2_pad = gpu_in2_pad[i];
		h_priv[i].d_in2_sub = gpu_in2_sub[i];
		h_priv[i].d_in2_sub2_sqr = gpu_in2_sub2_sqr[i];
		h_priv[i].d_tMask = gpu_tMask[i];
		h_priv[i].d_mask_conv = gpu_mask_conv[i];
		h_priv[i].in_partial_sum = gpu_in_partial_sum[i];
		h_priv[i].in_sqr_partial_sum = gpu_in_sqr_partial_sum[i];
		h_priv[i].par_max_val = gpu_par_max_val[i];
		h_priv[i].par_max_coo = gpu_par_max_coo[i];
	}

	for(i=pub.endoPoints; i<pub.allPoints; i++){
		h_priv[i].point_no = i - pub.endoPoints;
		h_priv[i].in_pointer = h_priv[i].point_no * pub.in_mod_elem;
		h_priv[i].d_Row = gpu_epiRow;
		h_priv[i].d_Col = gpu_epiCol;
		h_priv[i].d_tRowLoc = gpu_tEpiRowLoc;
		h_priv[i].d_tColLoc = gpu_tEpiColLoc;
		h_priv[i].d_T = gpu_epiT;
		h_priv[i].d_in2 = gpu_in2[i];
		h_priv[i].d_in2_sqr = gpu_in2_sqr[i];
		h_priv[i].d_in_mod = gpu_in_mod[i];
		h_priv[i].d_in_sqr = gpu_in_sqr[i];
		h_priv[i].d_conv = gpu_conv[i];
		h_priv[i].d_in2_pad = gpu_in2_pad[i];
		h_priv[i].d_in2_sub = gpu_in2_sub[i];
		h_priv[i].d_in2_sub2_sqr = gpu_in2_sub2_sqr[i];
		h_priv[i].d_tMask = gpu_tMask[i];
		h_priv[i].d_mask_conv = gpu_mask_conv[i];
		h_priv[i].in_partial_sum = gpu_in_partial_sum[i];
		h_priv[i].in_sqr_partial_sum = gpu_in_sqr_partial_sum[i];
		h_priv[i].par_max_val = gpu_par_max_val[i];
		h_priv[i].par_max_coo = gpu_par_max_coo[i];
	}

	// Copy private struct array to GPU
	private_struct* gpu_priv;
	cudaMalloc((void**)&gpu_priv, ALL_POINTS * sizeof(private_struct));
	cudaMemcpy(gpu_priv, h_priv, ALL_POINTS * sizeof(private_struct), cudaMemcpyHostToDevice);

	// GPU frame buffer
	fp* gpu_frame;
	cudaMalloc((void**)&gpu_frame, pub.frame_mem);

	printf("frame progress: ");
	fflush(NULL);

	// KERNEL LOOP
	for(pub.frame_no=0; pub.frame_no<frames_processed; pub.frame_no++){

		fp* h_frame = get_frame(pub.d_frames, pub.frame_no, 0, 0, 1);

		cudaMemcpy(gpu_frame, h_frame, pub.frame_mem, cudaMemcpyHostToDevice);
		free(h_frame);

		pub.d_frame = gpu_frame;

		int blockSize = 64;
		int gridSize = (pub.allPoints + blockSize - 1) / blockSize;
		kernel_gpu<<<gridSize, blockSize>>>(pub, gpu_priv);
		cudaDeviceSynchronize();

		printf("%d ", pub.frame_no);
		fflush(NULL);
	}

	printf("\n");
	fflush(NULL);

	// Copy results back to host
	cudaMemcpy(h_tEndoRowLoc, gpu_tEndoRowLoc, pub.d_endo_mem * pub.frames, cudaMemcpyDeviceToHost);
	cudaMemcpy(h_tEndoColLoc, gpu_tEndoColLoc, pub.d_endo_mem * pub.frames, cudaMemcpyDeviceToHost);
	cudaMemcpy(h_tEpiRowLoc, gpu_tEpiRowLoc, pub.d_epi_mem * pub.frames, cudaMemcpyDeviceToHost);
	cudaMemcpy(h_tEpiColLoc, gpu_tEpiColLoc, pub.d_epi_mem * pub.frames, cudaMemcpyDeviceToHost);

#ifdef OUTPUT
	write_data("result.txt",
		pub.frames,
		frames_processed,
		pub.endoPoints,
		h_tEndoRowLoc,
		h_tEndoColLoc,
		pub.epiPoints,
		h_tEpiRowLoc,
		h_tEpiColLoc);
#endif

	// Free GPU memory
	cudaFree(gpu_endoRow);
	cudaFree(gpu_endoCol);
	cudaFree(gpu_tEndoRowLoc);
	cudaFree(gpu_tEndoColLoc);
	cudaFree(gpu_endoT);
	cudaFree(gpu_epiRow);
	cudaFree(gpu_epiCol);
	cudaFree(gpu_tEpiRowLoc);
	cudaFree(gpu_tEpiColLoc);
	cudaFree(gpu_epiT);
	cudaFree(gpu_frame);
	cudaFree(gpu_priv);

	for(i=0; i<ALL_POINTS; i++){
		cudaFree(gpu_in2[i]);
		cudaFree(gpu_in2_sqr[i]);
		cudaFree(gpu_in_mod[i]);
		cudaFree(gpu_in_sqr[i]);
		cudaFree(gpu_conv[i]);
		cudaFree(gpu_in2_pad[i]);
		cudaFree(gpu_in2_sub[i]);
		cudaFree(gpu_in2_sub2_sqr[i]);
		cudaFree(gpu_tMask[i]);
		cudaFree(gpu_mask_conv[i]);
		cudaFree(gpu_in_partial_sum[i]);
		cudaFree(gpu_in_sqr_partial_sum[i]);
		cudaFree(gpu_par_max_val[i]);
		cudaFree(gpu_par_max_coo[i]);
	}

	free(gpu_in2); free(gpu_in2_sqr); free(gpu_in_mod); free(gpu_in_sqr);
	free(gpu_conv); free(gpu_in2_pad); free(gpu_in2_sub); free(gpu_in2_sub2_sqr);
	free(gpu_tMask); free(gpu_mask_conv);
	free(gpu_in_partial_sum); free(gpu_in_sqr_partial_sum);
	free(gpu_par_max_val); free(gpu_par_max_coo);

	free(h_endoRow); free(h_endoCol);
	free(h_tEndoRowLoc); free(h_tEndoColLoc);
	free(h_epiRow); free(h_epiCol);
	free(h_tEpiRowLoc); free(h_tEpiColLoc);

	return 0;
}

