__global__ void kernel_gpu_cuda(
    par_str par,
    dim_str dim,
    box_str* box,
    FOUR_VECTOR* rv,
    fp* qv,
    FOUR_VECTOR* fv)
{
    int l = blockIdx.x;
    if (l >= dim.number_boxes) return;

    int i = threadIdx.x;
    if (i >= NUMBER_PAR_PER_BOX) return;

    __shared__ FOUR_VECTOR rB_shared[NUMBER_PAR_PER_BOX];
    __shared__ fp qB_shared[NUMBER_PAR_PER_BOX];

    fp alpha = par.alpha;
    fp a2 = 2.0 * alpha * alpha;

    long first_i = box[l].offset;
    FOUR_VECTOR* rA = &rv[first_i];
    FOUR_VECTOR* fA = &fv[first_i];

    FOUR_VECTOR rAi = rA[i];
    fp fv_v = 0.0;
    fp fv_x = 0.0;
    fp fv_y = 0.0;
    fp fv_z = 0.0;

    int num_neighbors = 1 + box[l].nn;

    for (int k = 0; k < num_neighbors; k++) {
        int pointer;
        if (k == 0) {
            pointer = l;
        } else {
            pointer = box[l].nei[k-1].number;
        }

        long first_j = box[pointer].offset;
        FOUR_VECTOR* rB = &rv[first_j];
        fp* qB = &qv[first_j];

        rB_shared[i] = rB[i];
        qB_shared[i] = qB[i];
        __syncthreads();

        for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
            fp r2 = rAi.v + rB_shared[j].v - DOT(rAi, rB_shared[j]);
            fp u2 = a2 * r2;
            fp vij = exp(-u2);
            fp fs = 2.0 * vij;
            fp dx = rAi.x - rB_shared[j].x;
            fp dy = rAi.y - rB_shared[j].y;
            fp dz = rAi.z - rB_shared[j].z;
            fp fxij = fs * dx;
            fp fyij = fs * dy;
            fp fzij = fs * dz;

            fp q = qB_shared[j];
            fv_v += q * vij;
            fv_x += q * fxij;
            fv_y += q * fyij;
            fv_z += q * fzij;
        }

        __syncthreads();
    }

    fA[i].v += fv_v;
    fA[i].x += fv_x;
    fA[i].y += fv_y;
    fA[i].z += fv_z;
}

