#include <cuda_runtime.h>
#include <stdio.h>

#define BS 16

// Diagonal block kernel: performs LU factorization on the diagonal block
__global__ void lud_diagonal(float *a, int size, int offset)
{
    __shared__ float shadow[BS][BS];

    int tx = threadIdx.x;
    int ty = threadIdx.y;

    // Load the diagonal block into shared memory
    shadow[ty][tx] = a[(offset + ty) * size + (offset + tx)];
    __syncthreads();

    // Sequential LU factorization within the block
    for (int i = 0; i < BS; i++) {
        if (ty == i && tx >= i) {
            // Update row i, columns >= i (upper triangular part)
            float sum = shadow[i][tx];
            for (int k = 0; k < i; k++) {
                sum -= shadow[i][k] * shadow[k][tx];
            }
            shadow[i][tx] = sum;
        }
        __syncthreads();

        if (tx == i && ty > i) {
            // Update column i, rows > i (lower triangular part)
            float sum = shadow[ty][i];
            for (int k = 0; k < i; k++) {
                sum -= shadow[ty][k] * shadow[k][i];
            }
            shadow[ty][i] = sum / shadow[i][i];
        }
        __syncthreads();
    }

    // Write back
    a[(offset + ty) * size + (offset + tx)] = shadow[ty][tx];
}

// Perimeter kernel: updates top and left perimeter blocks
// Each block handles one BS×BS chunk of the perimeter
// blockIdx.x: chunk index (0..chunks_in_inter_row-1)
// blockIdx.y: 0 = top perimeter, 1 = left perimeter
__global__ void lud_perimeter(float *a, int size, int offset)
{
    __shared__ float dia[BS][BS];
    __shared__ float peri_row[BS][BS];
    __shared__ float peri_col[BS][BS];

    int tx = threadIdx.x;
    int ty = threadIdx.y;
    int chunk = blockIdx.x;

    // Load diagonal block
    dia[ty][tx] = a[(offset + ty) * size + (offset + tx)];

    // Top perimeter block position
    int top_col_offset = offset + BS + chunk * BS;
    // Left perimeter block position
    int left_row_offset = offset + BS + chunk * BS;

    // Load top perimeter block
    peri_row[ty][tx] = a[(offset + ty) * size + (top_col_offset + tx)];
    // Load left perimeter block
    peri_col[ty][tx] = a[(left_row_offset + ty) * size + (offset + tx)];

    __syncthreads();

    // Update top perimeter block
    // For each column j in the top block, for each row i:
    // a[offset+i][top_col+j] -= sum_{k<i} dia[i][k] * a[offset+k][top_col+j]
    {
        float sum = 0.f;
        // tx = column index j, ty = row index i
        // We need: for i from 0 to BS-1, for j from 0 to BS-1
        // peri_row[i][j] -= sum_{k<i} dia[i][k] * peri_row[k][j]
        // Each thread handles one (i,j) pair: ty=i, tx=j
        for (int k = 0; k < ty; k++) {
            sum += dia[ty][k] * peri_row[k][tx];
        }
        peri_row[ty][tx] -= sum;
    }

    __syncthreads();

    // Update left perimeter block
    // peri_col[i][j] = (peri_col[i][j] - sum_{k<j} peri_col[i][k]*dia[k][j]) / dia[j][j]
    // Each thread: ty=i, tx=j
    {
        float sum = 0.f;
        for (int k = 0; k < tx; k++) {
            sum += peri_col[ty][k] * dia[k][tx];
        }
        peri_col[ty][tx] = (peri_col[ty][tx] - sum) / dia[tx][tx];
    }

    __syncthreads();

    // Write back
    a[(offset + ty) * size + (top_col_offset + tx)] = peri_row[ty][tx];
    a[(left_row_offset + ty) * size + (offset + tx)] = peri_col[ty][tx];
}

// Interior kernel: updates interior blocks
// blockIdx.x = chunk_col, blockIdx.y = chunk_row
__global__ void lud_internal(float *a, int size, int offset)
{
    __shared__ float top[BS][BS];
    __shared__ float left[BS][BS];

    int tx = threadIdx.x;
    int ty = threadIdx.y;

    int col_chunk = blockIdx.x;
    int row_chunk = blockIdx.y;

    int i_global = offset + BS + row_chunk * BS;
    int j_global = offset + BS + col_chunk * BS;

    // Load top block: row (offset..offset+BS), col (j_global..j_global+BS)
    top[ty][tx] = a[(offset + ty) * size + (j_global + tx)];
    // Load left block: row (i_global..i_global+BS), col (offset..offset+BS)
    left[ty][tx] = a[(i_global + ty) * size + (offset + tx)];

    __syncthreads();

    float sum = 0.f;
    for (int k = 0; k < BS; k++) {
        sum += left[ty][k] * top[k][tx];
    }

    a[(i_global + ty) * size + (j_global + tx)] -= sum;
}

void lud_cuda(float *m, int matrix_dim)
{
    float *d_m;
    int size_bytes = matrix_dim * matrix_dim * sizeof(float);

    cudaMalloc((void**)&d_m, size_bytes);
    cudaMemcpy(d_m, m, size_bytes, cudaMemcpyHostToDevice);

    dim3 block(BS, BS);

    for (int offset = 0; offset < matrix_dim - BS; offset += BS) {
        // Step 1: Diagonal block
        lud_diagonal<<<1, block>>>(d_m, matrix_dim, offset);
        cudaDeviceSynchronize();

        int chunks = (matrix_dim - offset - BS) / BS;

        // Step 2: Perimeter blocks
        if (chunks > 0) {
            dim3 peri_grid(chunks, 1);
            lud_perimeter<<<peri_grid, block>>>(d_m, matrix_dim, offset);
            cudaDeviceSynchronize();

            // Step 3: Interior blocks
            dim3 inter_grid(chunks, chunks);
            lud_internal<<<inter_grid, block>>>(d_m, matrix_dim, offset);
            cudaDeviceSynchronize();
        }
    }

    // Final diagonal block
    int last_offset = ((matrix_dim / BS) - 1) * BS;
    // Handle the last block
    lud_diagonal<<<1, block>>>(d_m, matrix_dim, last_offset);
    cudaDeviceSynchronize();

    cudaMemcpy(m, d_m, size_bytes, cudaMemcpyDeviceToHost);
    cudaFree(d_m);
}

