)
{
#if REORDER_REF
    int bigx = refpos & 0x3FFFF;
    int bigy = refpos >> 18;
    int y = (bigy << 2) + (bigx & 0x3);
    int x = bigx >> 2;

	#if REFTEX
		return tex2D(reftex, x, y);
