#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <sys/time.h>

#define MAX_ARGS 10
#define REC_LENGTH 49
#define REC_WINDOW 10
#define LATITUDE_POS 28
#define OPEN 10000

struct neighbor {
    char entry[REC_LENGTH];
    double dist;
};

__global__ void compute_distances(char *d_sandbox, float *d_z, int rec_count,
                                   float target_lat, float target_long) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < rec_count) {
        char *rec_iter = d_sandbox + (i * REC_LENGTH + LATITUDE_POS - 1);

        // Parse latitude
        float tmp_lat = 0.0f;
        float tmp_long = 0.0f;

        char *p = rec_iter;
        float sign = 1.0f;
        if (*p == '-') { sign = -1.0f; p++; }
        else if (*p == '+') { p++; }
        // skip spaces
        while (*p == ' ') p++;
        float val = 0.0f;
        while (*p >= '0' && *p <= '9') {
            val = val * 10.0f + (*p - '0');
            p++;
        }
        if (*p == '.') {
            p++;
            float frac = 0.1f;
            while (*p >= '0' && *p <= '9') {
                val += (*p - '0') * frac;
                frac *= 0.1f;
                p++;
            }
        }
        tmp_lat = sign * val;

        // Parse longitude (offset by 5 from rec_iter)
        p = rec_iter + 5;
        sign = 1.0f;
        if (*p == '-') { sign = -1.0f; p++; }
        else if (*p == '+') { p++; }
        while (*p == ' ') p++;
        val = 0.0f;
        while (*p >= '0' && *p <= '9') {
            val = val * 10.0f + (*p - '0');
            p++;
        }
        if (*p == '.') {
            p++;
            float frac = 0.1f;
            while (*p >= '0' && *p <= '9') {
                val += (*p - '0') * frac;
                frac *= 0.1f;
                p++;
            }
        }
        tmp_long = sign * val;

        float dlat = tmp_lat - target_lat;
        float dlon = tmp_long - target_long;
        d_z[i] = sqrtf(dlat * dlat + dlon * dlon);
    }
}

int main(int argc, char* argv[]) {
    long long time0 = clock();
    FILE   *flist, *fp;
    int    i=0, j=0, k=0, rec_count=0, done=0;
    char   sandbox[REC_LENGTH * REC_WINDOW], dbname[64];
    struct neighbor *neighbors = NULL;
    float target_lat, target_long;

    if(argc < 5) {
        fprintf(stderr, "Invalid set of arguments\n");
        exit(-1);
    }

    flist = fopen(argv[1], "r");
    if(!flist) {
        printf("error opening flist\n");
        exit(1);
    }

    k = atoi(argv[2]);
