    else
        return k;
}

// Kernel for top-left anti-diagonal blocks
__global__ void needle_cuda_shared_1_kernel(int *referrence, int *matrix_cuda,
                                             int cols, int penalty, int blk)
{
    int b_index_x = blockIdx.x;
    int b_index_y = blk - 1 - b_index_x;

    int tx = threadIdx.x;

    __shared__ int temp[BLOCK_SIZE + 1][BLOCK_SIZE + 1];
    __shared__ int ref[BLOCK_SIZE][BLOCK_SIZE];

    // Load reference data - each thread loads one row
    for (int j = 0; j < BLOCK_SIZE; j++)
    {
        ref[tx][j] = referrence[cols * (b_index_y * BLOCK_SIZE + tx + 1) + b_index_x * BLOCK_SIZE + j + 1];
    }

    // Load input_itemsets border data - each thread loads one column
    for (int i = 0; i <= BLOCK_SIZE; i++)
    {
        temp[i][tx] = matrix_cuda[cols * (b_index_y * BLOCK_SIZE + i) + b_index_x * BLOCK_SIZE + tx];
    }

    __syncthreads();

    // Compute using wavefront (anti-diagonal) parallelism
    for (int m = 1; m <= BLOCK_SIZE; m++)
    {
        if (tx < m)
        {
            int i = tx + 1;
            int j = m - tx;
            temp[i][j] = maximum_cuda(
                temp[i - 1][j - 1] + ref[i - 1][j - 1],
                temp[i][j - 1] - penalty,
                temp[i - 1][j] - penalty);
        }
        __syncthreads();
    }

    for (int m = BLOCK_SIZE - 1; m >= 1; m--)
    {
        if (tx < m)
        {
            int i = tx + BLOCK_SIZE - m + 1;
            int j = BLOCK_SIZE - tx;
            temp[i][j] = maximum_cuda(
                temp[i - 1][j - 1] + ref[i - 1][j - 1],
                temp[i][j - 1] - penalty,
                temp[i - 1][j] - penalty);
        }
        __syncthreads();
    }

    // Write results back - each thread writes one column
    for (int i = 0; i < BLOCK_SIZE; i++)
    {
        matrix_cuda[cols * (b_index_y * BLOCK_SIZE + i + 1) + b_index_x * BLOCK_SIZE + tx + 1] = temp[i + 1][tx + 1];
    }
}

// Kernel for bottom-right anti-diagonal blocks
__global__ void needle_cuda_shared_2_kernel(int *referrence, int *matrix_cuda,
                                             int cols, int penalty, int blk, int block_width)
{
    int b_index_x = blockIdx.x + blk - 1;
    int b_index_y = block_width + blk - 2 - b_index_x;

    int tx = threadIdx.x;

    __shared__ int temp[BLOCK_SIZE + 1][BLOCK_SIZE + 1];
    __shared__ int ref[BLOCK_SIZE][BLOCK_SIZE];

    // Load reference data
    for (int j = 0; j < BLOCK_SIZE; j++)
    {
        ref[tx][j] = referrence[cols * (b_index_y * BLOCK_SIZE + tx + 1) + b_index_x * BLOCK_SIZE + j + 1];
    }

    // Load input_itemsets border data
    for (int i = 0; i <= BLOCK_SIZE; i++)
    {
        temp[i][tx] = matrix_cuda[cols * (b_index_y * BLOCK_SIZE + i) + b_index_x * BLOCK_SIZE + tx];
    }

    __syncthreads();

    // Compute
    for (int m = 1; m <= BLOCK_SIZE; m++)
    {
        if (tx < m)
        {
            int i = tx + 1;
            int j = m - tx;
            temp[i][j] = maximum_cuda(
                temp[i - 1][j - 1] + ref[i - 1][j - 1],
                temp[i][j - 1] - penalty,
                temp[i - 1][j] - penalty);
        }
        __syncthreads();
    }

    for (int m = BLOCK_SIZE - 1; m >= 1; m--)
    {
        if (tx < m)
        {
            int i = tx + BLOCK_SIZE - m + 1;
            int j = BLOCK_SIZE - tx;
            temp[i][j] = maximum_cuda(
                temp[i - 1][j - 1] + ref[i - 1][j - 1],
                temp[i][j - 1] - penalty,
                temp[i - 1][j] - penalty);
        }
        __syncthreads();
    }

    // Write results back
    for (int i = 0; i < BLOCK_SIZE; i++)
    {
        matrix_cuda[cols * (b_index_y * BLOCK_SIZE + i + 1) + b_index_x * BLOCK_SIZE + tx + 1] = temp[i + 1][tx + 1];
    }
}

void needle_cuda_shared_1(int *referrence, int *matrix_cuda,
                           int cols, int penalty, int blk, int block_width)
{
    dim3 dimGrid(blk, 1);
    dim3 dimBlock(BLOCK_SIZE, 1);
