/**
 * @file ex_particle_CUDA_naive_seq.cu
 * @brief Particle filter implementation in CUDA (double/naive precision)
 */
#include <stdlib.h>
#include <stdio.h>
#include <math.h>
#include <sys/time.h>
#include <cuda.h>
#include <limits.h>

#define PI 3.1415926535897932
#define BLOCK_SIZE 512

long M = INT_MAX;
int A = 1103515245;
int C = 12345;

long long get_time() {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (tv.tv_sec * 1000000) + tv.tv_usec;
}

float elapsed_time(long long start_time, long long end_time) {
    return (float)(end_time - start_time) / (1000 * 1000);
}

double roundDouble(double value) {
    int newValue = (int)(value);
    if (value - newValue < .5)
        return newValue;
    else
        return newValue++;
}

void setIf(int testValue, int newValue, int *array3D, int *dimX, int *dimY, int *dimZ) {
    int x, y, z;
    for (x = 0; x < *dimX; x++) {
        for (y = 0; y < *dimY; y++) {
            for (z = 0; z < *dimZ; z++) {
                if (array3D[x * *dimY * *dimZ + y * *dimZ + z] == testValue)
                    array3D[x * *dimY * *dimZ + y * *dimZ + z] = newValue;
            }
        }
    }
}

double randu(int *seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs(seed[index] / ((double)M));
}

double randn(int *seed, int index) {
    double u = randu(seed, index);
    double v = randu(seed, index);
    double cosine = cos(2.0 * PI * v);
    double rt = -2.0 * log(u);
    return sqrt(rt) * cosine;
}

void addNoise(int *array3D, int *dimX, int *dimY, int *dimZ, int *seed) {
    int x, y, z;
    for (x = 0; x < *dimX; x++) {
        for (y = 0; y < *dimY; y++) {
            for (z = 0; z < *dimZ; z++) {
                array3D[x * *dimY * *dimZ + y * *dimZ + z] =
                    array3D[x * *dimY * *dimZ + y * *dimZ + z] + (int)(5 * randn(seed, 0));
            }
        }
    }
}

void strelDisk(int *disk, int radius) {
    int diameter = radius * 2 - 1;
    int x, y;
    for (x = 0; x < diameter; x++) {
        for (y = 0; y < diameter; y++) {
            double distance = sqrt(pow((double)(x - radius + 1), 2) + pow((double)(y - radius + 1), 2));
            if (distance < radius)
                disk[x * diameter + y] = 1;
        }
    }
}

void dilate_matrix(int *matrix, int posX, int posY, int posZ, int dimX, int dimY, int dimZ, int error) {
    int startX = posX - error;
    while (startX < 0) startX++;
    int startY = posY - error;
    while (startY < 0) startY++;
    int endX = posX + error;
    while (endX > dimX) endX--;
    int endY = posY + error;
    while (endY > dimY) endY--;
    int x, y;
    for (x = startX; x < endX; x++) {
        for (y = startY; y < endY; y++) {
            double distance = sqrt(pow((double)(x - posX), 2) + pow((double)(y - posY), 2));
            if (distance < error)
                matrix[x * dimY * dimZ + y * dimZ + posZ] = 1;
        }
    }
}

void imdilate_disk(int *matrix, int dimX, int dimY, int dimZ, int error, int *newMatrix) {
    int x, y, z;
    for (z = 0; z < dimZ; z++) {
        for (x = 0; x < dimX; x++) {
            for (y = 0; y < dimY; y++) {
                if (matrix[x * dimY * dimZ + y * dimZ + z] == 1) {
                    dilate_matrix(newMatrix, x, y, z, dimX, dimY, dimZ, error);
                }
            }
        }
    }
}

void getneighbors(int *se, int numOnes, double *neighbors, int radius) {
    int x, y;
    int neighY = 0;
    int center = radius - 1;
    int diameter = radius * 2 - 1;
    for (x = 0; x < diameter; x++) {
        for (y = 0; y < diameter; y++) {
            if (se[x * diameter + y]) {
                neighbors[neighY * 2] = (int)(y - center);
                neighbors[neighY * 2 + 1] = (int)(x - center);
                neighY++;
            }
        }
    }
}

void videoSequence(int *I, int IszX, int IszY, int Nfr, int *seed) {
    int k;
    int max_size = IszX * IszY * Nfr;
    int x0 = (int)roundDouble(IszY / 2.0);
    int y0 = (int)roundDouble(IszX / 2.0);
    I[x0 * IszY * Nfr + y0 * Nfr + 0] = 1;

    int xk, yk, pos;
    for (k = 1; k < Nfr; k++) {
        xk = abs(x0 + (k - 1));
        yk = abs(y0 - 2 * (k - 1));
        pos = yk * IszY * Nfr + xk * Nfr + k;
        if (pos >= max_size)
            pos = 0;
        I[pos] = 1;
    }

    int *newMatrix = (int *)malloc(sizeof(int) * IszX * IszY * Nfr);
    imdilate_disk(I, IszX, IszY, Nfr, 5, newMatrix);
    int x, y;
    for (x = 0; x < IszX; x++) {
        for (y = 0; y < IszY; y++) {
            for (k = 0; k < Nfr; k++) {
                I[x * IszY * Nfr + y * Nfr + k] = newMatrix[x * IszY * Nfr + y * Nfr + k];
            }
        }
    }
    free(newMatrix);

    setIf(0, 100, I, &IszX, &IszY, &Nfr);
    setIf(1, 228, I, &IszX, &IszY, &Nfr);
    addNoise(I, &IszX, &IszY, &Nfr, seed);
}

/* CUDA Kernels */

__device__ double dev_randu(int *seed, int index) {
    int num = 1103515245 * seed[index] + 12345;
    seed[index] = num % INT_MAX;
    return fabs(seed[index] / ((double)INT_MAX));
}

__device__ double dev_randn(int *seed, int index) {
    double u = dev_randu(seed, index);
    double v = dev_randu(seed, index);
    double cosine = cos(2.0 * 3.1415926535897932 * v);
    double rt = -2.0 * log(u);
    return sqrt(rt) * cosine;
}

__global__ void kernel_motion_model(double *arrayX, double *arrayY, int *seed, int Nparticles) {
    int x = blockIdx.x * blockDim.x + threadIdx.x;
    if (x < Nparticles) {
        arrayX[x] += 1.0 + 5.0 * dev_randn(seed, x);
        arrayY[x] += -2.0 + 2.0 * dev_randn(seed, x);
    }
}

__global__ void kernel_likelihood(double *likelihood, int *I, double *arrayX, double *arrayY,
                                   double *objxy, int *ind, int countOnes, int Nparticles,
                                   int IszY, int Nfr, int k, int max_size) {
    int x = blockIdx.x * blockDim.x + threadIdx.x;
    if (x < Nparticles) {
        int y;
        int indX, indY;
        for (y = 0; y < countOnes; y++) {
            indX = (int)round(arrayX[x]) + (int)objxy[y * 2 + 1];
            indY = (int)round(arrayY[x]) + (int)objxy[y * 2];
            ind[x * countOnes + y] = (int)fabs((double)(indX * IszY * Nfr + indY * Nfr + k));
            if (ind[x * countOnes + y] >= max_size)
                ind[x * countOnes + y] = 0;
        }
        likelihood[x] = 0.0;
        for (y = 0; y < countOnes; y++) {
            double val = (double)I[ind[x * countOnes + y]];
            likelihood[x] += (pow(val - 100.0, 2) - pow(val - 228.0, 2)) / 50.0;
        }
        likelihood[x] = likelihood[x] / ((double)countOnes);
    }
}

__global__ void kernel_update_weights(double *weights, double *likelihood, int Nparticles) {
    int x = blockIdx.x * blockDim.x + threadIdx.x;
    if (x < Nparticles) {
        weights[x] = weights[x] * exp(likelihood[x]);
    }
}

__global__ void kernel_normalize_weights(double *weights, double sumWeights, int Nparticles) {
    int x = blockIdx.x * blockDim.x + threadIdx.x;
    if (x < Nparticles) {
        weights[x] = weights[x] / sumWeights;
    }
}

__global__ void kernel_sum_weights(double *weights, double *sum_out, int Nparticles) {
    __shared__ double sdata[BLOCK_SIZE];
    int tid = threadIdx.x;
    int x = blockIdx.x * blockDim.x + tid;
    sdata[tid] = 0.0;
    if (x < Nparticles) {
        sdata[tid] = weights[x];
    }
    __syncthreads();
    for (int s = blockDim.x / 2; s > 0; s >>= 1) {
        if (tid < s) {
            sdata[tid] += sdata[tid + s];
        }
        __syncthreads();
    }
    if (tid == 0) {
        atomicAdd(sum_out, sdata[0]);
    }
}

__global__ void kernel_estimate(double *arrayX, double *arrayY, double *weights,
                                 double *xe_out, double *ye_out, int Nparticles) {
    __shared__ double sxe[BLOCK_SIZE];
    __shared__ double sye[BLOCK_SIZE];
    int tid = threadIdx.x;
    int x = blockIdx.x * blockDim.x + tid;
    sxe[tid] = 0.0;
    sye[tid] = 0.0;
    if (x < Nparticles) {
        sxe[tid] = arrayX[x] * weights[x];
        sye[tid] = arrayY[x] * weights[x];
    }
    __syncthreads();
    for (int s = blockDim.x / 2; s > 0; s >>= 1) {
        if (tid < s) {
            sxe[tid] += sxe[tid + s];
            sye[tid] += sye[tid + s];
        }
        __syncthreads();
    }
    if (tid == 0) {
        atomicAdd(xe_out, sxe[0]);
        atomicAdd(ye_out, sye[0]);
    }
}

__global__ void kernel_compute_u(double *u, double u1, int Nparticles) {
    int x = blockIdx.x * blockDim.x + threadIdx.x;
    if (x < Nparticles) {
        u[x] = u1 + x / ((double)Nparticles);
    }
}

__global__ void kernel_resample(double *CDF, double *u, double *arrayX, double *arrayY,
                                 double *xj, double *yj, int Nparticles) {
    int j = blockIdx.x * blockDim.x + threadIdx.x;
    if (j < Nparticles) {
        int i = -1;
        for (int x = 0; x < Nparticles; x++) {
            if (CDF[x] >= u[j]) {
                i = x;
                break;
            }
        }
        if (i == -1) i = Nparticles - 1;
        xj[j] = arrayX[i];
        yj[j] = arrayY[i];
    }
}

__global__ void kernel_reset(double *arrayX, double *arrayY, double *xj, double *yj,
                              double *weights, int Nparticles) {
    int x = blockIdx.x * blockDim.x + threadIdx.x;
    if (x < Nparticles) {
        arrayX[x] = xj[x];
        arrayY[x] = yj[x];
        weights[x] = 1.0 / ((double)Nparticles);
    }
}

void particleFilter(int *I, int IszX, int IszY, int Nfr, int *seed, int Nparticles) {
    int max_size = IszX * IszY * Nfr;
    long long start = get_time();

    double xe = roundDouble(IszY / 2.0);
    double ye = roundDouble(IszX / 2.0);

    int radius = 5;
    int diameter = radius * 2 - 1;
    int *disk = (int *)malloc(diameter * diameter * sizeof(int));
    strelDisk(disk, radius);
    int countOnes = 0;
    int x, y;
    for (x = 0; x < diameter; x++) {
        for (y = 0; y < diameter; y++) {
            if (disk[x * diameter + y] == 1)
                countOnes++;
        }
    }
    double *objxy = (double *)malloc(countOnes * 2 * sizeof(double));
    getneighbors(disk, countOnes, objxy, radius);

    long long get_neighbors = get_time();
    printf("TIME TO GET NEIGHBORS TOOK: %f\n", elapsed_time(start, get_neighbors));

    double *weights = (double *)malloc(sizeof(double) * Nparticles);
    for (x = 0; x < Nparticles; x++) {
        weights[x] = 1.0 / ((double)Nparticles);
    }

    long long get_weights = get_time();
    printf("TIME TO GET WEIGHTSTOOK: %f\n", elapsed_time(get_neighbors, get_weights));

    double *likelihood = (double *)malloc(sizeof(double) * Nparticles);
    double *arrayX = (double *)malloc(sizeof(double) * Nparticles);
    double *arrayY = (double *)malloc(sizeof(double) * Nparticles);
    double *xj = (double *)malloc(sizeof(double) * Nparticles);
    double *yj = (double *)malloc(sizeof(double) * Nparticles);
    double *CDF = (double *)malloc(sizeof(double) * Nparticles);
    double *u = (double *)malloc(sizeof(double) * Nparticles);
    int *ind = (int *)malloc(sizeof(int) * countOnes * Nparticles);

    for (x = 0; x < Nparticles; x++) {
        arrayX[x] = xe;
        arrayY[x] = ye;
    }

    int *d_I;
    double *d_weights, *d_likelihood, *d_arrayX, *d_arrayY;
    double *d_xj, *d_yj, *d_CDF, *d_u, *d_objxy;
    int *d_ind, *d_seed;
    double *d_xe, *d_ye, *d_sum;

    cudaMalloc((void **)&d_I, sizeof(int) * IszX * IszY * Nfr);
    cudaMalloc((void **)&d_weights, sizeof(double) * Nparticles);
    cudaMalloc((void **)&d_likelihood, sizeof(double) * Nparticles);
    cudaMalloc((void **)&d_arrayX, sizeof(double) * Nparticles);
    cudaMalloc((void **)&d_arrayY, sizeof(double) * Nparticles);
    cudaMalloc((void **)&d_xj, sizeof(double) * Nparticles);
    cudaMalloc((void **)&d_yj, sizeof(double) * Nparticles);
    cudaMalloc((void **)&d_CDF, sizeof(double) * Nparticles);
    cudaMalloc((void **)&d_u, sizeof(double) * Nparticles);
    cudaMalloc((void **)&d_objxy, sizeof(double) * countOnes * 2);
    cudaMalloc((void **)&d_ind, sizeof(int) * countOnes * Nparticles);
    cudaMalloc((void **)&d_seed, sizeof(int) * Nparticles);
    cudaMalloc((void **)&d_xe, sizeof(double));
    cudaMalloc((void **)&d_ye, sizeof(double));
    cudaMalloc((void **)&d_sum, sizeof(double));

    cudaMemcpy(d_I, I, sizeof(int) * IszX * IszY * Nfr, cudaMemcpyHostToDevice);
    cudaMemcpy(d_weights, weights, sizeof(double) * Nparticles, cudaMemcpyHostToDevice);
    cudaMemcpy(d_arrayX, arrayX, sizeof(double) * Nparticles, cudaMemcpyHostToDevice);
    cudaMemcpy(d_arrayY, arrayY, sizeof(double) * Nparticles, cudaMemcpyHostToDevice);
    cudaMemcpy(d_objxy, objxy, sizeof(double) * countOnes * 2, cudaMemcpyHostToDevice);
    cudaMemcpy(d_seed, seed, sizeof(int) * Nparticles, cudaMemcpyHostToDevice);

    int blocks = (Nparticles + BLOCK_SIZE - 1) / BLOCK_SIZE;

    printf("TIME TO SET ARRAYS TOOK: %f\n", elapsed_time(get_weights, get_time()));

    int k;
    for (k = 1; k < Nfr; k++) {
        long long set_arrays = get_time();

        kernel_motion_model<<<blocks, BLOCK_SIZE>>>(d_arrayX, d_arrayY, d_seed, Nparticles);
        cudaDeviceSynchronize();

        long long error_time = get_time();
        printf("TIME TO SET ERROR TOOK: %f\n", elapsed_time(set_arrays, error_time));

        kernel_likelihood<<<blocks, BLOCK_SIZE>>>(d_likelihood, d_I, d_arrayX, d_arrayY,
                                                   d_objxy, d_ind, countOnes, Nparticles,
                                                   IszY, Nfr, k, max_size);
        cudaDeviceSynchronize();

        long long likelihood_time = get_time();
        printf("TIME TO GET LIKELIHOODS TOOK: %f\n", elapsed_time(error_time, likelihood_time));

        kernel_update_weights<<<blocks, BLOCK_SIZE>>>(d_weights, d_likelihood, Nparticles);
        cudaDeviceSynchronize();

        long long exponential = get_time();
        printf("TIME TO GET EXP TOOK: %f\n", elapsed_time(likelihood_time, exponential));

        double zero = 0.0;
        cudaMemcpy(d_sum, &zero, sizeof(double), cudaMemcpyHostToDevice);
        kernel_sum_weights<<<blocks, BLOCK_SIZE>>>(d_weights, d_sum, Nparticles);
        cudaDeviceSynchronize();

        long long sum_time = get_time();
        printf("TIME TO SUM WEIGHTS TOOK: %f\n", elapsed_time(exponential, sum_time));

        double sumWeights;
        cudaMemcpy(&sumWeights, d_sum, sizeof(double), cudaMemcpyDeviceToHost);

        kernel_normalize_weights<<<blocks, BLOCK_SIZE>>>(d_weights, sumWeights, Nparticles);
        cudaDeviceSynchronize();

        long long normalize = get_time();
        printf("TIME TO NORMALIZE WEIGHTS TOOK: %f\n", elapsed_time(sum_time, normalize));

        double h_xe = 0.0, h_ye = 0.0;
        cudaMemcpy(d_xe, &h_xe, sizeof(double), cudaMemcpyHostToDevice);
        cudaMemcpy(d_ye, &h_ye, sizeof(double), cudaMemcpyHostToDevice);
        kernel_estimate<<<blocks, BLOCK_SIZE>>>(d_arrayX, d_arrayY, d_weights, d_xe, d_ye, Nparticles);
        cudaDeviceSynchronize();
        cudaMemcpy(&h_xe, d_xe, sizeof(double), cudaMemcpyDeviceToHost);
        cudaMemcpy(&h_ye, d_ye, sizeof(double), cudaMemcpyDeviceToHost);
        xe = h_xe;
        ye = h_ye;

        long long move_time = get_time();
        printf("TIME TO MOVE OBJECT TOOK: %f\n", elapsed_time(normalize, move_time));
        printf("XE: %lf\n", xe);
        printf("YE: %lf\n", ye);
        double distance = sqrt(pow((double)(xe - (int)roundDouble(IszY / 2.0)), 2) +
                               pow((double)(ye - (int)roundDouble(IszX / 2.0)), 2));
        printf("%lf\n", distance);

        cudaMemcpy(weights, d_weights, sizeof(double) * Nparticles, cudaMemcpyDeviceToHost);
        CDF[0] = weights[0];
        for (x = 1; x < Nparticles; x++) {
            CDF[x] = weights[x] + CDF[x - 1];
        }
        cudaMemcpy(d_CDF, CDF, sizeof(double) * Nparticles, cudaMemcpyHostToDevice);

        long long cum_sum = get_time();
        printf("TIME TO CALC CUM SUM TOOK: %f\n", elapsed_time(move_time, cum_sum));

        cudaMemcpy(seed, d_seed, sizeof(int) * Nparticles, cudaMemcpyDeviceToHost);
        double u1 = (1.0 / ((double)Nparticles)) * randu(seed, 0);
        cudaMemcpy(d_seed, seed, sizeof(int) * Nparticles, cudaMemcpyHostToDevice);

        kernel_compute_u<<<blocks, BLOCK_SIZE>>>(d_u, u1, Nparticles);
        cudaDeviceSynchronize();

        long long u_time = get_time();
        printf("TIME TO CALC U TOOK: %f\n", elapsed_time(cum_sum, u_time));

        kernel_resample<<<blocks, BLOCK_SIZE>>>(d_CDF, d_u, d_arrayX, d_arrayY, d_xj, d_yj, Nparticles);
        cudaDeviceSynchronize();

        long long xyj_time = get_time();
        printf("TIME TO CALC NEW ARRAY X AND Y TOOK: %f\n", elapsed_time(u_time, xyj_time));

        kernel_reset<<<blocks, BLOCK_SIZE>>>(d_arrayX, d_arrayY, d_xj, d_yj, d_weights, Nparticles);
        cudaDeviceSynchronize();

        long long reset = get_time();
        printf("TIME TO RESET WEIGHTS TOOK: %f\n", elapsed_time(xyj_time, reset));
    }

    cudaMemcpy(seed, d_seed, sizeof(int) * Nparticles, cudaMemcpyDeviceToHost);

    cudaFree(d_I);
    cudaFree(d_weights);
    cudaFree(d_likelihood);
    cudaFree(d_arrayX);
    cudaFree(d_arrayY);
    cudaFree(d_xj);
    cudaFree(d_yj);
    cudaFree(d_CDF);
    cudaFree(d_u);
    cudaFree(d_objxy);
    cudaFree(d_ind);
    cudaFree(d_seed);
    cudaFree(d_xe);
    cudaFree(d_ye);
    cudaFree(d_sum);

    free(disk);
    free(objxy);
    free(weights);
    free(likelihood);
    free(xj);
    free(yj);
    free(arrayX);
    free(arrayY);
    free(CDF);
    free(u);
    free(ind);
}

int main(int argc, char *argv[]) {
    char *usage = "openmp.out -x <dimX> -y <dimY> -z <Nfr> -np <Nparticles>";
    if (argc != 9) {
        printf("%s\n", usage);
        return 0;
    }
    if (strcmp(argv[1], "-x") || strcmp(argv[3], "-y") || strcmp(argv[5], "-z") || strcmp(argv[7], "-np")) {
        printf("%s\n", usage);
        return 0;
    }

    int IszX, IszY, Nfr, Nparticles;

    if (sscanf(argv[2], "%d", &IszX) == EOF) {
        printf("ERROR: dimX input is incorrect");
        return 0;
    }
    if (IszX <= 0) {
        printf("dimX must be > 0\n");
        return 0;
    }
    if (sscanf(argv[4], "%d", &IszY) == EOF) {
        printf("ERROR: dimY input is incorrect");
        return 0;
    }
    if (IszY <= 0) {
        printf("dimY must be > 0\n");
        return 0;
    }
    if (sscanf(argv[6], "%d", &Nfr) == EOF) {
        printf("ERROR: Number of frames input is incorrect");
        return 0;
    }
    if (Nfr <= 0) {
        printf("number of frames must be > 0\n");
        return 0;
    }
    if (sscanf(argv[8], "%d", &Nparticles) == EOF) {
        printf("ERROR: Number of particles input is incorrect");
        return 0;
    }
    if (Nparticles <= 0) {
        printf("Number of particles must be > 0\n");
        return 0;
    }

    int *seed = (int *)malloc(sizeof(int) * Nparticles);
    int i;
    for (i = 0; i < Nparticles; i++)
        seed[i] = time(0) * i;

    int *I = (int *)malloc(sizeof(int) * IszX * IszY * Nfr);
    long long start = get_time();
    videoSequence(I, IszX, IszY, Nfr, seed);
    long long endVideoSequence = get_time();
    printf("VIDEO SEQUENCE TOOK %f\n", elapsed_time(start, endVideoSequence));
    particleFilter(I, IszX, IszY, Nfr, seed, Nparticles);
