#include <stdio.h>
#include <math.h>
#include "srad.h"

__global__ void srad_kernel_1(
    float *d_J,
    float *d_C,
    float *d_dN,
    float *d_dS,
    float *d_dW,
    float *d_dE,
    int *d_iN,
    int *d_iS,
    int *d_jW,
    int *d_jE,
    float q0sqr,
    int rows,
    int cols
)
{
    int j = blockIdx.x * blockDim.x + threadIdx.x;
    int i = blockIdx.y * blockDim.y + threadIdx.y;

    if (i >= rows || j >= cols) return;

    int k = i * cols + j;
    float Jc = d_J[k];

    float dN_val = d_J[d_iN[i] * cols + j] - Jc;
    float dS_val = d_J[d_iS[i] * cols + j] - Jc;
    float dW_val = d_J[i * cols + d_jW[j]] - Jc;
    float dE_val = d_J[i * cols + d_jE[j]] - Jc;

    d_dN[k] = dN_val;
    d_dS[k] = dS_val;
    d_dW[k] = dW_val;
    d_dE[k] = dE_val;

    float G2 = (dN_val * dN_val + dS_val * dS_val
              + dW_val * dW_val + dE_val * dE_val) / (Jc * Jc);

    float L = (dN_val + dS_val + dW_val + dE_val) / Jc;

    float num = (0.5f * G2) - ((1.0f / 16.0f) * (L * L));
    float den = 1.0f + (0.25f * L);
    float qsqr = num / (den * den);

    den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
    float c_val = 1.0f / (1.0f + den);

    if (c_val < 0.0f) c_val = 0.0f;
    else if (c_val > 1.0f) c_val = 1.0f;

    d_C[k] = c_val;
}

__global__ void srad_kernel_2(
    float *d_J,
    float *d_C,
    float *d_dN,
    float *d_dS,
    float *d_dW,
    float *d_dE,
    int *d_iS,
    int *d_jE,
    float lambda,
    int rows,
    int cols
)
{
    int j = blockIdx.x * blockDim.x + threadIdx.x;
    int i = blockIdx.y * blockDim.y + threadIdx.y;

    if (i >= rows || j >= cols) return;

    int k = i * cols + j;

    float cN = d_C[k];
    float cS = d_C[d_iS[i] * cols + j];
    float cW = d_C[k];
    float cE = d_C[i * cols + d_jE[j]];

    float D = cN * d_dN[k] + cS * d_dS[k] + cW * d_dW[k] + cE * d_dE[k];

    d_J[k] = d_J[k] + 0.25f * lambda * D;
}

void srad_cuda_1(
    float *d_J,
    float *d_C,
    float *d_dN,
    float *d_dS,
    float *d_dW,
    float *d_dE,
    int *d_iN,
    int *d_iS,
    int *d_jW,
    int *d_jE,
    float q0sqr,
    int rows,
    int cols
)
{
    dim3 block(BLOCK_SIZE, BLOCK_SIZE);
    dim3 grid((cols + BLOCK_SIZE - 1) / BLOCK_SIZE,
              (rows + BLOCK_SIZE - 1) / BLOCK_SIZE);

    srad_kernel_1<<<grid, block>>>(
        d_J, d_C, d_dN, d_dS, d_dW, d_dE,
        d_iN, d_iS, d_jW, d_jE,
        q0sqr, rows, cols
    );
    cudaDeviceSynchronize();
}

void srad_cuda_2(
    float *d_J,
    float *d_C,
    float *d_dN,
    float *d_dS,
    float *d_dW,
    float *d_dE,
    int *d_iS,
    int *d_jE,
    float lambda,
    int rows,
    int cols
)
{
    dim3 block(BLOCK_SIZE, BLOCK_SIZE);
    dim3 grid((cols + BLOCK_SIZE - 1) / BLOCK_SIZE,
              (rows + BLOCK_SIZE - 1) / BLOCK_SIZE);

    srad_kernel_2<<<grid, block>>>(
        d_J, d_C, d_dN, d_dS, d_dW, d_dE,
        d_iS, d_jE,
        lambda, rows, cols
    );
    cudaDeviceSynchronize();
}

