#ifndef STREAMCLUSTER_HEADER_CU
#define STREAMCLUSTER_HEADER_CU

#include <stdio.h>
#include <iostream>
#include <fstream>
#include <stdlib.h>
#include <sys/time.h>
#include <string.h>
#include <assert.h>
#include <math.h>
#include <sys/resource.h>
#include <limits.h>

using namespace std;

#define MAXNAMESIZE 1024
#define SEED 1
#define SP 1
#define ITER 3
#define CACHE_LINE 512
#define PROFILE
#define THREADS_PER_BLOCK 512
#define MAXBLOCKS 65536

typedef struct {
  float weight;
  float *coord;
  long assign;
  float cost;
} Point;

typedef struct {
  long num;
  int dim;
  Point *p;
} Points;

extern bool *switch_membership;
extern bool* is_center;
extern int* center_table;
extern float* block;
extern int nproc;
extern int c, d;

#ifdef PROFILE
extern double time_local_search;
extern double time_speedy;
extern double time_select_feasible;
extern double time_gain;
extern double time_shuffle;
extern double time_gain_dist;
extern double time_gain_init;
#endif

double gettime();

float dist(Point p1, Point p2, int dim);

class PStream {
public:
  virtual size_t read( float* dest, int dim, int num ) = 0;
  virtual int ferror() = 0;
  virtual int feof() = 0;
  virtual ~PStream() {}
};

class SimStream : public PStream {
public:
  SimStream(long n_) { n = n_; }
  size_t read( float* dest, int dim, int num ) {
    size_t count = 0;
    for( int i = 0; i < num && n > 0; i++ ) {
      for( int k = 0; k < dim; k++ ) {
        dest[i*dim + k] = lrand48()/(float)INT_MAX;
      }
      n--;
      count++;
    }
    return count;
  }
  int ferror() { return 0; }
  int feof() { return n <= 0; }
  ~SimStream() {}
private:
  long n;
};

class FileStream : public PStream {
public:
  FileStream(char* filename) {
    fp = fopen( filename, "rb");
    if( fp == NULL ) {
      fprintf(stderr,"error opening file %s\n.",filename);
      exit(1);
    }
  }
  size_t read( float* dest, int dim, int num ) {
    return std::fread(dest, sizeof(float)*dim, num, fp);
  }
  int ferror() { return std::ferror(fp); }
  int feof() { return std::feof(fp); }
  ~FileStream() {
    printf("closing file stream\n");
    fclose(fp);
  }
private:
  FILE* fp;
};

void streamCluster(PStream* stream, long kmin, long kmax, int dim,
                   long chunksize, long centersize, char* outfile);

